---jump 1, 国内老玩家跳过; 2,国外根据地区跳过; 3,卡指引容错跳过; 4,跑酷小游戏跳过主线; 5,躺平小游戏跳过主线
function ModelGuide:GuideJumpResp(pb)
    self._waitJumpNewPlot = false
    local jump = pb.jump
    if jump then
        if jump == 1 or jump == 2 then
            self._waitJumpNewPlot = true
            gLGpManager:FindStoryCopyGp():StopStory()
            gLGpManager:FindNewbieGp():StopStory()
            self:CheckExecuteJump()
        elseif jump == 3 then
            self:DealJumpType3()
        end
    end
end

function ModelGuide:DealJumpType3()
    gLGpManager:FindStoryCopyGp():StopStory()
    gLGameUI:CloseAllButExcept()

    FireEvent(EventNames.REFRESH_FUNCTION_STATE)
    --设置默认阵型
    local combatType = LCombatTypeConst.COMBAT_MAIN
    if not gModelFormation:IsAnyValidHeroInFormation(combatType) or gModelInstance:IsAutoOneKeyUp() then
        gModelBattle:DoOneKeyMainFormation()
    end

    local defaultMap = "LCityMap"
    if gModelPlayer:IsNoName() then
        --if gModelPlot:IsPrologueOpen() then
        defaultMap = "LStoryMap"
        --end

        GF.OpenWnd('UIPerCreateName', { isNew = true })

    end

    GF.ChangeMap(defaultMap)
end

function ModelGuide:InitGuideData()
    local data = self._guideInfoResp

    self._triggeredGuideType = nil

    self._triggeredId = {}
    for k, v in ipairs(data.guides) do
        self._triggeredId[v] = true

        local data = self._conditions[v]
        if data and data.guideType > 0 then
            self._triggeredGuideType = data.guideType
        end
    end

    self:InitTriggerList()
    local record = data.progress

    self._isDataInit = true
    if self._combatResult then
        self:OnMainAccount(self._combatResult)
    end

    self._serverTrigger = self:GetServerTrigger(data.keepGuides)

    if record > 0 then
        self._waitGuideId = self:GetAgain(record)
    else
        local serverOpenDay = gLGameLogin:GetServerOpenDay()
        self:OnTrigger(26, serverOpenDay)
    end
end

