function ModelGuide:OnWndOpenTrigger(wndPara)
    local wndName = wndPara.wndName
    local page = wndPara.para1 or 1
    local subPage = wndPara.para2 or 1

    if wndName == "UIFightPrepare" then
        local combatType = wndPara.argList and wndPara.argList["combatType"]
        if combatType == LCombatTypeConst.COMBAT_TACTICAL_TRAINING then
            return
        end
    elseif wndName == "UISowEffect" then
        local wndType = wndPara.argList and wndPara.argList["wndType"]
        if page ~= wndType then
            return
        end
    end

    local para = string.format("%s=%s=%s", wndName, page, subPage)

    self:OnTrigger(24, para)

end

function ModelGuide:CheckTriggerType40(changeIdMap)
    local itemRefId = 0
    local conditionRefId = 0
    if not changeIdMap then
        return
    end

    for k, v in pairs(changeIdMap) do
        if self._guideItemChangeMapId[k] then
            itemRefId = k
            conditionRefId = self._guideItemChangeMapId[k]
            break
        end
    end

    local itemNum = gModelItem:GetNumByRefId(itemRefId)
    if not itemNum then
        return
    end

    -- 
    local para_40 = {}
    para_40.itemRefId = itemRefId
    para_40.conditionRefId = conditionRefId
    para_40.itemNum = itemNum
    self:CheckGuideStartCommon(40, para_40)
    --self:OnTrigger(40,itemNum)
end

function ModelGuide:OnTrigger(type, para)
    if PRODUCT_G_VER ~= 0 then
        --提审屏蔽指引
        return
    end
    if self:IsInGuide() then
        return
    end
    printInfoN(string.format("trigger type %s para %s", type, para))
    local guidePara = {
        type = type,
        para = para,
    }
    local guideData = self:GetWaitTriggerGuide(guidePara)
    if not guideData then
        return
    end
    local guideId = self:GetTriggerGuide(guideData)
    if guideId == 0 then
        return
    end

    local key = guideData.key
    local isCanGuide = true
    if self._checkCanGuideFunc[key] then

        isCanGuide = self._checkCanGuideFunc[key]()
    end

    if not isCanGuide then
        return
    end

    if not self._isEnterMain then
        self._waitGuide = guideData
        return
    end

    self:StartGuide(guideId, guideData)
end

function ModelGuide:GetTriggerGuide(guideData)
    local guideList = guideData.guideList
    if not guideList then
        return 0
    end
    local defaultGuide = guideList[0]
    if defaultGuide then
        return defaultGuide
    end

    local curIndex = 1
    local wnd = GF.FindFirstWndByName("UIMCity")
    if wnd then
        curIndex = wnd:GetCurIndex()
    end
    local guide = guideList[curIndex]
    if guide then
        return guide
    end
    return 0
end

function ModelGuide:OnTriggerSoft(type, para)
    ---弱指引中断后再次触发
    local curGuide = self:GetCurGuide()

    if curGuide <= 0 then
        return
    end
    local cfg = GameTable.NewPlayerGuideEventRef[curGuide]
    if not cfg then
        return
    end

    if cfg.type ~= ModelGuide.SOFT then
        return
    end

    local trigger = self._softCondition[curGuide]
    if trigger then
        if trigger.type == type and trigger.para == para then
            self:StartGuide(curGuide)
        end
    end

end

function ModelGuide:InitTriggerList()
    local guideType = self:GetGuideType()

    self._triggerConditionList = {}
    for k, v in pairs(self._conditions) do
        if v.canRepeat or not self._triggeredId[k] and (v.guideType == 0 or v.guideType == guideType) then
            table.insert(self._triggerConditionList, v)
        end
    end
end

