function ModelGuide:IsJumpFeedScene()
    if self._bJumpFeedScene then
        LogWarn("检测成功 直流拦截")
    else
        LogWarn("检测成功 不拦截")
    end
    return self._bJumpFeedScene
end

function ModelGuide:CheckIsJumpFeedScene()
    --- 仅一次判断
    if not self._checkJumpFeedScene then
        self._checkJumpFeedScene = true
        if gLSdkImpl and gLSdkImpl:CallMethod(LSdkMethod.CheckCanJumpFeedScene) then
            LogWarn("检测成功 设置拦截")
            self:SetJumpFeedScene()
            return true
        else
            LogWarn("检测成功 CheckCanJumpFeedScene 失败")
        end
    end
    return false
end

function ModelGuide:SetJumpFeedScene()
    self._bJumpFeedScene = true
end

function ModelGuide:StartGuide(refId, guideData, extraData)
    if self:CheckIsJumpFeedScene() then
        return 
    end
    if self:IsJumpFeedScene() then
        return 
    end
    
    if PRODUCT_G_VER ~= 0 then
        return
    end --提审屏蔽
    gLxTKData:OnGuideStep(refId)

    --gLxTKData:OnTAClientEventReq(LxTKData.CLIENT_GUIDE,nil,refId)
    local key = 0
    if guideData then
        table.removeidata(self._triggerConditionList, guideData)
        key = guideData.key
        self._triggeredId[key] = true
    end

    self:GuideChangeReq(key, { refId })

    if LOG_INFO_ENABLED then
        print("当前指引 refid " .. refId)
    end
    local cfg = GameTable.NewPlayerGuideEventRef[refId]
    if not cfg then
        printErrorN("not guide cfg id " .. refId)
        self:EndGuide()
        return
    end

    FireEvent(EventNames.ON_GUIDE_START)

    local wndType = extraData and extraData.wndType
    local targetTran = extraData and extraData.targetTran
    GF.OpenUIGue("UIGue", { refId = refId, wndType = wndType, targetTran = targetTran })

end

function ModelGuide:EndGuide()
    local curGuide = self:GetCurGuide()
    local skipList = self:GetSkipGuides(curGuide)
    table.insert(skipList, -1)

    self:GuideChangeReq(0, skipList)

    local wndGuide = GF.FindFirstWndByName("UIGue")
    if wndGuide then
        wndGuide:OnGuideEnd()
    end

    if self._endCall then
        self._endCall()
        self._endCall = nil
    end

    FireEvent(EventNames.ON_GUIDE_END)
end

