function ModelGuide:OnNextGuide(guideId)
    local nextGuide = self:GetNextGuideId(guideId)
    if nextGuide == guideId then
        LogError("loop guide" .. guideId)
        self:EndGuide()
        return
    end

    if nextGuide == 0 then
        self:EndGuide()
    else
        local ref = self:GetGuideEventConfig(guideId)
        local delay = ref.delay / 1000
        if delay > 0 then
            self:DelayExecuteGuide(nextGuide, delay)
        else
            self:StartGuide(nextGuide)
        end
    end
end

