function ModelGuide:ParseConfig()
    self._isParseConfig = true

    self._conditions = {}

    for k, v in pairs(GameTable.NewPlayerGuideConditionRef) do
        local mark = v.mark
        local guideId = v.guideId
        local guideList = self:ParseNextGuide(guideId)

        local sort = v.sort
        local preCondition = v.fristCondition
        local prePara = nil
        if not string.isempty(preCondition) then
            prePara = self:ParsePreCondition(preCondition)
        end

        local triPara = self:ParseCondition(v.condition)

        local data = {
            key = k,
            guideList = guideList,
            canRepeat = mark == 0,
            prePara = prePara,
            triPara = triPara,
            sort = sort,
            markFight = v.markFight,
            guideType = v.type,
        }
        self._conditions[k] = data


        --检查下对应的triPara有无40类型
        for i, j in ipairs(triPara) do
            if checknumber(j.type) == 40 then
                local itemPara = string.split(j.para, "=")
                local itemRefId = checknumber(itemPara[1])
                self._guideItemChangeMapId[itemRefId] = k
            end
        end
    end

    self._softCondition = {}
    for k, v in pairs(GameTable.NewPlayerGuideEventRef) do
        local condition = v.condition
        if not string.isempty(condition) then
            self._softCondition[k] = self:ParseCondition(condition)
        end
    end

    self._keepUpGuides = {}
    local value = GameTable.NewPlayerGuideConfigRef["keepUpGuide"]
    local numbers = LxDataHelper.ParseIntParam_Comma(value)
    for k, v in ipairs(numbers) do
        self._keepUpGuides[v] = true
    end

    self._jumpGuideIds = {}
    value = GameTable.NewPlayerGuideConfigRef["jumpGuideRefId"]
    numbers = LxDataHelper.ParseIntParam_Comma(value)
    for k, v in ipairs(numbers) do
        self._jumpGuideIds[v] = true
    end

end

function ModelGuide:ParseCondition(str)
    if string.isempty(str) then
        return {}
    end
    local dataList = {}
    local strs = string.split(str, ',')
    for k, v in ipairs(strs) do
        local s, e = string.find(v, "=")
        local type, para
        if s and e then
            type = string.sub(v, 1, e - 1)
            para = string.sub(v, e + 1, string.len(v))
        end

        local t = {
            type = type,
            para = para
        }
        table.insert(dataList, t)
    end

    return dataList
end

function ModelGuide:ParsePreCondition(str)
    if string.isempty(str) then
        return {}
    end

    local dataList = {}
    local strs = string.split(str, ',')
    for k, v in ipairs(strs) do
        local tempStrs = string.split(v, '=')
        local data = {
            type = tempStrs[1],
            para = tempStrs[2],
        }
        table.insert(dataList, data)

    end

    return dataList

end

function ModelGuide:ParseNextGuide(str)
    if string.isempty(str) then
        return nil
    end
    local temp = string.split(str, ',')
    local list = {}
    for k, v in ipairs(temp) do
        local tempTemp = string.split(v, '=')
        if #tempTemp >= 2 then
            local type = tonumber(tempTemp[1])
            local guide = tonumber(tempTemp[2])
            list[type] = guide
        end
    end
    return list
end
function ModelGuide:GetWaitTriggerGuide(param)
    if not self._isDataInit then
        printInfoN("data not init GetWaitTriggerGuide")
        return
    end
    local type = param.type
    local para = param.para

    local triggered = {}

    for k, v in pairs(self._triggerConditionList) do
        local prePara = v.prePara
        local isPass = true
        if prePara then
            isPass = self:CheckPrePara(prePara, param)
        end

        if isPass then
            local isHit = false
            local isFill = true
            for k1, v1 in ipairs(v.triPara) do
                local targetType = tonumber(v1.type)
                if targetType == type then
                    if type == 7 then
                        --等级
                        local targetLv = tonumber(v1.para)
                        if targetLv > para.oldLv and targetLv <= para.newLv then
                            isHit = true
                        end
                    elseif type == 26 then
                        --开服天数
                        if tonumber(para) >= tonumber(v1.para) then
                            isHit = true
                        end
                    elseif type == 40 then
                        local tempPara = string.split(v1.para, "=")
                        local itemId = checknumber(tempPara[1])
                        local itemNum = gModelItem:GetNumByRefId(itemId) or 0
                        local checkNum = checknumber(tempPara[2])
                        if itemNum >= tonumber(checkNum) then
                            isHit = true
                        end

                    else
                        if v1.para == tostring(para) then
                            isHit = true
                        end
                    end
                else
                    if targetType == 26 then
                        --开服天数
                        local targetDay = tonumber(v1.para)
                        local dayPast = gLGameLogin:GetServerOpenDay()
                        if dayPast < targetDay then
                            isFill = false
                            break
                        end
                    elseif targetType == 2 then
                        --主线通关
                        local targetNode = tonumber(v1.para)
                        local isPassed = gModelInstance:IsBattleNodePass(targetNode)
                        if not isPassed then
                            isFill = false
                            break
                        end
                    elseif targetType == 7 then
                        --等级
                        local targetLv = tonumber(v1.para)
                        local curLv = gModelPlayer:GetPlayerLv()
                        if curLv < targetLv then
                            isFill = false
                            break
                        end
                    elseif targetType == 40 then

                        local tempPara = string.split(v1.para, "=")
                        local itemId = checknumber(tempPara[1])
                        local itemNum = gModelItem:GetNumByRefId(itemId) or 0
                        local checkNum = checknumber(tempPara[2])
                        if itemNum < tonumber(checkNum) then
                            isFill = false
                            break
                        end
                    else
                        isFill = false
                        break
                    end
                end
            end

            if isHit and isFill then
                table.insert(triggered, v)
            end
        end
    end

    if #triggered == 0 then
        return
    end
    table.sort(triggered, function(a, b)
        return a.sort < b.sort
    end)
    local guideData = triggered[1]

    return guideData
end
function ModelGuide:SetWaitGuideByNode(battleNode)
    --需要延迟触发的指引
    local para = {
