function ModelGuide:CheckGuideByLittleGame(refId, bNoReward)
    local para = {
        type = 38,
        para = refId
    }

    if bNoReward then
        self:OnTrigger(para.type, para.refId)
        return
    end

    local guideData = self:GetWaitTriggerGuide(para)
    if guideData then
        self._waitGuide = guideData
        printInfoN("CheckGuideByLittleGame wait guide " .. tostring(guideData.key))
    end
end

function ModelGuide:CheckGuideStartCommon(type, para)
    local triPra = {
        type = type,
        para = para,
    }
    local guideData = self:GetWaitTriggerGuide(triPra)

    if not guideData then
        return
    end

    self._waitGuide = guideData

    local wndMap = {
        ["UIAward"] = true
    }

    if gLGameUI:IsExistOneWnd(wndMap) then
        return
    end

    self:CheckStartWaitGuide()
end

function ModelGuide:CheckStartWaitGuide()
    if PRODUCT_G_VER ~= 0 then
        --提审屏蔽
        return
    end
    if not self._isEnterMain then
        return
    end

    if self:IsInGuide() then
        return
    end

    if self._waitGuide then
        local guideData = self._waitGuide
        self._waitGuide = nil
        local guideId = self:GetTriggerGuide(guideData)
        if guideId > 0 then
            self:StartGuide(guideId, guideData)
            return true
        end
    end
end

function ModelGuide:OnEnterCityMap()
    if self._isEnterMain then
        --第一次进入检测
        return
    end
    self._isEnterMain = true
    if self:IsInGuide() then
        return
    end

    local waitGuideId = self._waitGuideId
    self._waitGuideId = nil
    if waitGuideId and waitGuideId > 0 then
        self:StartGuide(waitGuideId)
        return
    end

    if self:CheckStartWaitGuide() then
        return
    end

    local isStart = self:StartServerTrigger()
    if not isStart then
        self:StartLeastCheckGuide()
    end
end

function ModelGuide:CheckShowFinger()

    local lastOperTime = self:GetOperTime()
    local now = GetTimestamp()
    local past = now - lastOperTime
    local delay = gModelInstance:GetInstancePara("ChangeBtnGuideTime")

    if delay > past then
        return false
    end

    local isInGuide = self:IsInGuide()
    if isInGuide then
        return false
    end
    local canEnter = false
    local battleNode = gModelInstance:GetRawBattleNode()
    if battleNode == -1 then
        local chapter = gModelInstance:GetNextChapterId()
        if chapter > 0 then
            battleNode = gModelInstance:GetChapterFirstNode(chapter)
            canEnter = gModelInstance:CanEnterBattleNode(battleNode)
        end
    else
        canEnter = gModelInstance:CanEnterBattleNode(battleNode)
    end
    if not canEnter then
        return false
    end

    local nextCfg = gModelInstance:GetMissionCfg(battleNode)
    if not nextCfg then
        return false
    end

    local monsterRefId = nextCfg.monster
    local power = gModelHero:GetMonsterPower(monsterRefId)
    if power == 0 then
        return false
    end

    local ownPower = gModelPower:GetMaxMainPower() --gModelPlayer:GetPlayerFightPower()
    local ratio = ownPower / power
    local configRatio = gModelInstance:GetInstancePara("ChangeBtnGuideCombat")
    if ratio < configRatio then
        return false
    end

    local level = gModelPlayer:GetPlayerLv()
    local lvLimit = gModelInstance:GetInstancePara("ChangeBtnGuideLv")
    if level > lvLimit then
        return false
    end

    if not self._operTime then
        self._operTime = GetTimestamp()
    end

    return true
end

