function ModelGuide:CheckPrePara(prePara, triPara)

    local includeNode = {}
    if triPara and triPara.type == 2 then
        includeNode = { [tonumber(triPara.para)] = true }
    end

    for k, v in ipairs(prePara) do
        local type = tonumber(v.type)
        if type == 11 then
            --互斥指引
            local guideId = tonumber(v.para)
            local isTriggered = self._triggeredId[guideId]
            if isTriggered then
                return false
            end
        elseif type == 12 then
            --首冲
            if gModelPlayer:IsCharged() then
                return false
            end
        elseif type == 26 then
            --开服天数
            local day = tonumber(v.para)
            local dayPast = gLGameLogin:GetServerOpenDay()
            if dayPast < day then
                return false
            end
        elseif type == 7 then
            --等级
            local lv = tonumber(v.para)
            local meLv = gModelPlayer:GetPlayerLv()
            if meLv < lv then
                return false
            end
        elseif type == 27 then
            --是否可一键升星
            if not gModelHeroSpirit:CheckAutoUpStarHeroStatus() then
                return false
            end
        elseif type == 2 then
            --关卡通关
            local node = tonumber(v.para)
            if not gModelInstance:IsBattleNodePass(node) and not includeNode[node] then
                return false
            end
        elseif type == 29 then
            --可一键领取主线奖励
            local canGet = gModelInstance:CanQuickGetPassReward(includeNode)
            local value = canGet and 1 or 0
            if value ~= tonumber(v.para) then
                return false
            end
        elseif type == 36 then
            -- 关卡未通关
            local node = tonumber(v.para)
            if gModelInstance:IsBattleNodePass(node) then
                return false
            end
        elseif type == 41 then
            -- 神裔爵位赛未开启 为true
            if gModelArena:IsPeakOpen() then
                return false
            end
            return true
        elseif type == 43 then
            -- 角色的背包中是否不包含神话
            if gModelHero:IsHaveAnyHeroGreaterOrEqualToQuality(6) then
                return false
            end
        elseif type == 44 then
            -- 判断角色背包中，是否有某个角色
            local refId = tonumber(v.para)
            if not gModelHero:IsHaveAnyHeroByRefId(refId) then
                return false
            end
        end
    end

    return true
end

function ModelGuide:GetServerTrigger(guideList)
    if not guideList or #guideList <= 0 then
        return
    end

    local guideType = self:GetGuideType()

    local dataList = {}
    for k, v in ipairs(guideList) do
        local guideData = self._conditions[v]
        if guideData then
            if not self._triggeredId[v] and (guideData.guideType == 0 or guideType == guideData.guideType) then
                local prePara = guideData.prePara
                if not prePara or self:CheckPrePara(prePara) then
                    local data = {
                        key = v,
                        sort = guideData.sort,
                    }

                    table.insert(dataList, data)
                end
            end
        end

    end

    table.sort(dataList, function(a, b)
        return a.sort < b.sort
    end)
    local data = dataList[1]
    if data then
        return data.key
    end
end

function ModelGuide:StartServerTrigger()
    local guideKey = self._serverTrigger
    if not guideKey then
        return
    end
    --if self._triggeredId[guideKey] then
    --    return
    --end
    local guideData = self._conditions[guideKey]
    if not guideData then
        return
    end

    --local prePara = guideData.prePara
    --if prePara then
    --    local canTrigger = self:CheckPrePara(prePara)
    --    if not canTrigger then
    --        return
    --    end
    --end
    local triggerGuide = self:GetTriggerGuide(guideData)
    if triggerGuide == 0 then
        return
    end
    self:StartGuide(triggerGuide, guideData)
    return true
end

function ModelGuide:StartLeastCheckGuide()

    local triggeredList = {}
    for k, v in pairs(self._triggerConditionList) do
        local canTrigger = true
        if v.prePara then
            canTrigger = self:CheckPrePara(v.prePara)
        end
        if canTrigger then
            local triPara = v.triPara
            if self:ConditionPass(triPara) then
                table.insert(triggeredList, v)
            end
        end

    end

    if #triggeredList == 0 then
        return
    end
    table.sort(triggeredList, function(a, b)
        return a.sort < b.sort
    end)
    local guideData = triggeredList[1]
    local triggerGuide = self:GetTriggerGuide(guideData)
    if triggerGuide == 0 then
        return
    end
    self:StartGuide(triggerGuide, guideData)
end

function ModelGuide:ConditionPass(triPara)

    local curLv = gModelPlayer:GetPlayerLv()
    for k, v in pairs(triPara) do
        local type = tonumber(v.type)
        if type == 2 then
            local targetNode = tonumber(v.para)
            local pass = gModelInstance:IsBattleNodePass(targetNode)
            if not pass then
                return false
            end
        elseif type == 26 then
            local dayPast = gLGameLogin:GetServerOpenDay()
            if dayPast <= tonumber(v.para) then
                return false
            end
        elseif type == 7 then
            if curLv <= tonumber(v.para) then
                return false
            end
        else
            return false
        end
    end

    return true
end

function ModelGuide:IsAllowPopWnd()
    local guide = self:GetGuidePara("tipsGuide")
    if self._triggeredId then
        local isAllow = self._triggeredId[guide]
        return isAllow or false
    end
    return false
end

function ModelGuide:IsMeetJumpNewPlot()

    --if true then
    --    return true
    --end

    if self:AllowSkipPrologue() then
        return false
    end

    local serverList = gLGameLogin:GetMyPlayerServerList()
    if not serverList then
        return false
    end

    local palyerInfoList = gLGameLogin:GetPlayerInfoList() or {}
    local guideJumpLv = self:GetGuidePara("guideJumpLv")
    local canJump = false
    for k, v in pairs(serverList) do
        local fid = v.id
        local playerInfo = palyerInfoList[fid]
        if not table.isempty(playerInfo) then
            local lvl = tonumber(playerInfo.level or 0)
            if lvl >= guideJumpLv then
                canJump = true
                break
            end
        end
    end

    return canJump
end

