function ModelGuide:CheckExecuteJump()
    if self._waitJumpNewPlot then
        local includeWndList = {
            ["UISy"] = true,
            ["UIFightPrepare"] = true,
            ["UINeie"] = true,
        }

        if gLGameUI:IsCurMainClean(includeWndList) then
            self._waitJumpNewPlot = false
            --触发新手剧情跳过逻辑
            gModelPlot:JumpNewPlot()
        end
    end
end

function ModelGuide:GMFinishGuide(key)
    for k, v in ipairs(self._triggerConditionList) do
        if v.key == key then
            table.remove(self._triggerConditionList, k)
            break
        end
    end
    self._triggeredId[key] = true
    self:GuideChangeReq(key, { -1 })
end

