    local record = tonumber(LPlayerPrefs.formationGuide) or 0
    if formationRefId <= record then
        return true
    end

    return false
end

function ModelGuide:RecordFormationGuide(formationRefId)
    LPlayerPrefs.SetFormationGuide(tostring(formationRefId))
end

function ModelGuide:GetSkipGuides(refId)
    local record = {}
    local list = {}
    local curGuide = refId
    while true do
        local nextGuide = self:GetNextGuideId(curGuide)
        if nextGuide <= 0 then
            break
        end
        if record[nextGuide] then
            break
        end
        record[nextGuide] = true
        table.insert(list, nextGuide)
        curGuide = nextGuide
    end

    return list
end

function ModelGuide:IsSkipPrologueArea(symbol)
    local parseFunc = function(value)
        local strList = string.split(value, ",")
        local record = {}
        for k, v in ipairs(strList) do
            record[v] = true
        end

        return record
    end
    local skipAreaRecord = self:GetParaConfigValueImpl("NewPlayerGuideConfigRef", "guideSkipArea", parseFunc)

    if skipAreaRecord then
        return skipAreaRecord[symbol]
    end

end

function ModelGuide:IsNormalGuideType()
    local guideType = self:GetGuideType()
    return self._normalStartGuideMap[guideType]
end
function ModelGuide:AllowSkipPrologue()
    local isNormal = self:IsNormalGuideType()

    if not isNormal then
        return
    end
    --local guideType = self:GetGuideType()
    --if guideType and guideType ~= 1 then
    --    return
    --end

    local skip = self:GetGuidePara("guideSkipPlot")
    if skip ~= 1 then
        return
    end

    if gLGameLanguage:IsKoreaRegion() then
        return
    end

    local regionSymbol = gModelPay:GetMoneyTypeGild()
    if not self:IsSkipPrologueArea(regionSymbol) then
        return
    end

    return true
end

function ModelGuide:IsBattleNodeTrigger()
    if not self._waitGuide then
        return
    end

    if self._waitGuide.markFight ~= 1 then
        return
    end

    for k, v in pairs(self._waitGuide.triPara) do
        if tonumber(v.type) == 2 then
            return true
        end
    end
end

