---type 1:通关10100 2:通关10150 3:通关10300
function ModelGuide:OnBattleNodePass(battleNode)
    if battleNode == 10100 then
        self._waitSdkGameGuide = 1
    elseif battleNode == 10150 then
        self._waitSdkGameGuide = 2
    elseif battleNode == 10300 then
        self._waitSdkGameGuide = 3
    end

end

