function ModelGuide:IsAddFrontStep()
    local showCartoon = gModelGuide:GetGuidePara("guideGameCartoon4001") ~= 0
    return showCartoon
end

function ModelGuide:CheckShowCartoon()
    local addStep = self:IsAddFrontStep()
    local isFirst = gLGameLogin:GetPlayCartoon()
    return isFirst and addStep
end

function ModelGuide:CheckShowCreateName()
    local addStep = self:IsAddFrontStep()
    local isNoName = gModelPlayer:IsNoName()
    return addStep and isNoName
end

return ModelGuide